import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.Pywvta2k.js";const _=JSON.parse('{"title":"脉经","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/02-魏晋隋唐/01-脉经（王叔和）.md","filePath":"tcm-data/02-魏晋隋唐/01-脉经（王叔和）.md","lastUpdated":1781084559000}'),o={name:"tcm-data/02-魏晋隋唐/01-脉经（王叔和）.md"};function n(i,t,s,d,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="脉经" tabindex="-1">脉经 <a class="header-anchor" href="#脉经" aria-label="Permalink to &quot;脉经&quot;">​</a></h1><blockquote><p>王叔和（西晋，约210-280年），山东高平人 中医第一部脉学专著，集魏晋以前脉学大成</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：西晋（约公元260年）</li><li><strong>卷数</strong>：10卷</li><li><strong>学术地位</strong>：中医脉学的奠基之作</li><li><strong>重要贡献</strong>：王叔和还是《伤寒杂病论》的主要整理者——<strong>没有王叔和，我们可能看不到仲景的著作</strong></li></ul><hr><h2 id="二、核心内容" tabindex="-1">二、核心内容 <a class="header-anchor" href="#二、核心内容" aria-label="Permalink to &quot;二、核心内容&quot;">​</a></h2><h3 id="_1-24种脉象分类" tabindex="-1">1. 24种脉象分类 <a class="header-anchor" href="#_1-24种脉象分类" aria-label="Permalink to &quot;1. 24种脉象分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">脉象（共24种）</th></tr></thead><tbody><tr><td style="text-align:left;">浮脉类</td><td style="text-align:left;">浮、洪、濡、散、芤</td></tr><tr><td style="text-align:left;">沉脉类</td><td style="text-align:left;">沉、伏、弱、牢</td></tr><tr><td style="text-align:left;">迟脉类</td><td style="text-align:left;">迟、缓、涩、结</td></tr><tr><td style="text-align:left;">数脉类</td><td style="text-align:left;">数、促、动</td></tr><tr><td style="text-align:left;">虚脉类</td><td style="text-align:left;">虚、微、细、代、短</td></tr><tr><td style="text-align:left;">实脉类</td><td style="text-align:left;">实、滑、紧、长、弦</td></tr></tbody></table><h3 id="_2-寸口脉与脏腑对应" tabindex="-1">2. 寸口脉与脏腑对应 <a class="header-anchor" href="#_2-寸口脉与脏腑对应" aria-label="Permalink to &quot;2. 寸口脉与脏腑对应&quot;">​</a></h3><p>左：寸（心、小肠）→ 关（肝、胆）→ 尺（肾、膀胱） 右：寸（肺、大肠）→ 关（脾、胃）→ 尺（命门、三焦）</p><h3 id="_3-脉证合参" tabindex="-1">3. 脉证合参 <a class="header-anchor" href="#_3-脉证合参" aria-label="Permalink to &quot;3. 脉证合参&quot;">​</a></h3><blockquote><p><strong>「脉证相参，乃可万全。」</strong></p></blockquote><p>王叔和强调：<strong>不能单凭脉象断病，必须结合症状</strong>。这一原则是后世&quot;四诊合参&quot;的先导。</p><hr><h2 id="三、经典名言" tabindex="-1">三、经典名言 <a class="header-anchor" href="#三、经典名言" aria-label="Permalink to &quot;三、经典名言&quot;">​</a></h2><blockquote><p><strong>「脉理精微，其体难辨。弦紧浮芤，展转相类。在心易了，指下难明。」</strong></p></blockquote><blockquote><p><strong>「谓沉为伏，则方治永乖；以缓为迟，则危殆立至。」</strong></p></blockquote><hr><h2 id="四、对后世的影响" tabindex="-1">四、对后世的影响 <a class="header-anchor" href="#四、对后世的影响" aria-label="Permalink to &quot;四、对后世的影响&quot;">​</a></h2><ul><li><strong>李时珍《濒湖脉学》</strong>：以《脉经》为基础，作27种脉象歌诀</li><li><strong>黄元御《四圣心源》</strong>：脉法解，以升降浮沉解脉理</li><li>诊脉至今仍是中医四诊的核心</li></ul>',21)])])}const u=e(o,[["render",n]]);export{_ as __pageData,u as default};
